#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(Int c=(a);c>=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=110;
namespace Sub1
{
	double dp[N];inline void mian()
	{
		int n=read();dp[1]=0;rep(2,n,i)dp[i]=dp[i-1]+2.0/i;
		printf("%.6lf",dp[n]);return;
	}
}
namespace Sub2
{
	double dp[N][N];inline void mian()
	{
		int n=read();rep(1,n,i)dp[i][0]=1;
		rep(2,n,i)rep(1,i-1,j){rep(1,i-1,k)dp[i][j]+=dp[k][j-1]+dp[i-k][j-1]-dp[k][j-1]*dp[i-k][j-1];dp[i][j]/=(double)(i-1);}
		double ans=0;rep(1,n,i)ans+=dp[n][i];printf("%.6lf\n",ans);
	}
}
int main(){read()==1?Sub1::mian():Sub2::mian();return 0;}
